import{_ as e,o as a,c as r,ae as t}from"./chunks/framework.BugOhmHL.js";const g=JSON.parse('{"title":"Configuração do GitHub","description":"","frontmatter":{},"headers":[],"relativePath":"guia/github.md","filePath":"guia/github.md"}'),s={name:"guia/github.md"};function i(n,o,c,d,u,l){return a(),r("div",null,[...o[0]||(o[0]=[t('<h1 id="configuracao-do-github" tabindex="-1">Configuração do GitHub <a class="header-anchor" href="#configuracao-do-github" aria-label="Permalink to &quot;Configuração do GitHub&quot;">​</a></h1><p>Para que a Snapport funcione como sua &quot;Fonte Única de Verdade&quot;, você precisa organizar seus repositórios no GitHub seguindo algumas convenções simples.</p><h2 id="_1-selecao-de-projetos-tags" tabindex="-1">1. Seleção de Projetos (Tags) <a class="header-anchor" href="#_1-selecao-de-projetos-tags" aria-label="Permalink to &quot;1. Seleção de Projetos (Tags)&quot;">​</a></h2><p>A biblioteca não lista todos os seus repositórios automaticamente. Ela busca apenas aqueles que você marcou especificamente para o seu portfólio.</p><ul><li><strong>Tag de Descoberta</strong>: Por padrão, a Snapport procura pela tag <code>port</code>.</li><li><strong>Como configurar</strong>: Vá até o seu repositório no GitHub, clique no ícone de engrenagem em &quot;About&quot; e adicione <code>port</code> na seção de <strong>Topics</strong>.</li></ul><blockquote><p><strong>Dica</strong>: Você pode usar uma tag customizada passando a propriedade <code>tag</code> na inicialização da lib.</p></blockquote><h2 id="_2-definindo-as-stacks-topics" tabindex="-1">2. Definindo as Stacks (Topics) <a class="header-anchor" href="#_2-definindo-as-stacks-topics" aria-label="Permalink to &quot;2. Definindo as Stacks (Topics)&quot;">​</a></h2><p>A biblioteca ignora o campo automático &quot;Language&quot; do GitHub para evitar que ferramentas de build (como arquivos gerados de CSS/HTML) poluam seus filtros.</p><p>Para que os filtros e as categorias funcionem corretamente:</p><ul><li>Liste as tecnologias reais que você usou nos <strong>Topics</strong> do repositório (ex: <code>react</code>, <code>typescript</code>, <code>nodejs</code>, <code>sass</code>).</li><li><strong>Importante</strong>: A Snapport possui um mapeamento interno de cores e ícones. Para que a estilização automática funcione, o nome do tópico deve seguir o padrão reconhecido pela lib.</li><li>Você pode conferir a <strong><a href="./stacks.html">Lista de Stacks Compatíveis</a></strong> para garantir que está usando os termos corretos.</li></ul><h2 id="_3-gestao-de-imagens-preview-png" tabindex="-1">3. Gestão de Imagens (preview.png) <a class="header-anchor" href="#_3-gestao-de-imagens-preview-png" aria-label="Permalink to &quot;3. Gestão de Imagens (preview.png)&quot;">​</a></h2><p>A Snapport busca uma imagem de capa diretamente no seu repositório para garantir a melhor performance.</p><ul><li><strong>Arquivo</strong>: Você deve criar um arquivo chamado <code>preview.png</code> na raiz (root) do seu repositório.</li><li><strong>Regra de Ouro</strong>: O nome deve ser <strong>exatamente</strong> <code>preview.png</code> (letras minúsculas). O GitHub diferencia maiúsculas de minúsculas (<em>case-sensitive</em>).</li><li><strong>Proporção</strong>: Recomendamos o uso da proporção <strong>16:9</strong> (ex: 1280x720px) para evitar cortes nos cards.</li></ul><h3 id="estrategia-de-fallback" tabindex="-1">Estratégia de Fallback <a class="header-anchor" href="#estrategia-de-fallback" aria-label="Permalink to &quot;Estratégia de Fallback&quot;">​</a></h3><p>Caso você esqueça do arquivo ou ocorra algum erro, a lib possui um sistema de segurança em cascata:</p><ol><li>Tenta carregar o seu <code>preview.png</code>.</li><li>Se não existir, tenta o <strong>GitHub Open Graph</strong> (a imagem social do repo).</li><li>Se tudo falhar, gera um <strong>Placeholder</strong> neutro com o nome do projeto.</li></ol>',16)])])}const m=e(s,[["render",i]]);export{g as __pageData,m as default};
